var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>승자로서 카나리아 스쿼드에 대한 평가는?</color>","JPN":"<color=#ffd34c>勝者として、カナリア・スクワッドについての評価は？</color>","ENG":"<color=#ffd34c>As the winning team, what was your impression of Canary Squad?</color>","TWN":"<color=#ffd34c>作為獲勝的一方，你會怎麼評價金絲雀小隊？</color>"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"각자의 기량은 준수했어요. 신예 팀이라고는 믿기지 않았습니다.","JPN":"各々の器量は素晴らしかったです。新設のチームとは信じられないくらいでした。","ENG":"Each member was powerful on their own. I couldn't believe they were rookies.","TWN":"每個人的技術都很優秀，說她們是新銳隊伍，我都有點不敢相信。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"하지만 결국 전술의 차이가 승패를 결정지었다고 생각합니다.","JPN":"ですが、結局は戦術の差が勝敗を決したと思いますね。","ENG":"However, when it comes to battle, it all comes down to tactics.","TWN":"不過我認為是因為戰術的差異而分出勝負的。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"리더는 저돌적이어선 안 돼요. 항상 냉철하게 팀 전체를 관조해야죠.","JPN":"リーダーは猪突猛進であってはなりません。いつも冷静にチーム全体を見れないと。","ENG":"Leaders should never be aggressive. They must always take a step back and observe the situation with a cool head.","TWN":"作為隊長不能衝動，必須經常冷靜地審視全隊的狀況。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>발전의 여지가 있다고 보시나요?</color>","JPN":"<color=#ffd34c>発展の見込みはあると思いますか？</color>","ENG":"<color=#ffd34c>Do you think that they have potential?</color>","TWN":"<color=#ffd34c>你認為她們還有發展的餘地嗎？</color>"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"카나리아 스쿼드의 리더는 한눈에 봐도 굉장히 어려 보였습니다.","JPN":"カナリア・スクワッドのリーダーはぱっと見にはとても幼く見えました。","ENG":"Canary Squad's leader looked very young.","TWN":"金絲雀小隊的隊長一看就知道年紀很小。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"마지막에 있었던 판단 미스도 그 나이 또래를 감안하면 이상하지 않아요.","JPN":"最後の判断ミスも、その歳を考えるとおかしくありません。","ENG":"I understand why she made that mistake at the end, considering her age.","TWN":"考慮到她的年齡，她最後的判斷失準也不足為奇。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그러니 지금은 더 많은 경험을 해 보라고 말해 주고 싶군요.","JPN":"ですが、今はもっと色々な経験をしてみた方がいいと助言したいです。","ENG":"I suggest that she experience many different things first.","TWN":"所以現在我想對她說，多積累一些經驗吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"하하, 어쩌면 그 과정에서 건틀렛보다 더 잘 맞는 진로를 찾을 수 있을지도 모르니까요.","JPN":"はは、もしかしたらその過程で、ガントレットよりも適性の合う職業を見つけられるかもしれませんしね。","ENG":"Ha ha, who knows? Maybe she'll find something that suits her more than the Gauntlet.","TWN":"哈哈，說不定你可以在這個過程中，找到比聖鎧更適合發展的領域。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"또 발작이네. 아까운 핸드폰은 왜 집어던져.","JPN":"また発作か？　スマホもったいないから投げるなよ。","ENG":"Another tantrum. What are you throwing the phone for?","TWN":"又來了。幹嘛要摔手機，摔壞多可惜。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"화가 안 나게 생겼어요?","JPN":"これが怒らないでいられると思うの？","ENG":"Aren't you angry?!","TWN":"我能不生氣嗎？"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"본선 진출이 인생 업적인 삼류 팀 주제에 우릴 체험학습 나온 어린애 취급하잖아요.","JPN":"本戦進出しか業績のない三流チームのくせに、私たちを体験学習でもしに来た子どもみたいに言ったのよ。","ENG":"The only thing that moron accomplished in his life was making it to the elimination rounds. He treated us like kids on a field trip!","TWN":"一個人生最大成就就是擠進過決賽的三流隊伍，居然把我們當成來體驗學習的小孩子。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이대로는 <color=#ffd34c>그 여자</color> 이전에 그릴 파티의 바보들에게도 웃음거리가 될 거라고요!","JPN":"このままじゃ、<color=#ffd34c>あの女</color>以前に、グリルパーティーのバカどもの嘲笑の的になるわ！","ENG":"At this rate, we'll be nothing but clowns to those idiots in Grill Party, let alone get to <color=#ffd34c>her</color>!","TWN":"照這樣下去，在見到<color=#ffd34c>那女人</color>之前，我會先淪為格里爾派提那群傻子的笑柄的！"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아무튼 졌잖아. 그 삼류 팀에게. 패자는 변명할 권리 없어.","JPN":"負けたのは事実だろ？　その三流チームに。敗者は言い訳する権利すらないんだよ。","ENG":"Well, the fact is that we lost. To those morons. We don't get to make excuses.","TWN":"反正就是輸啦，沒什麼好辯解的。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"변명이……!","JPN":"言い訳じゃ……！","ENG":"It's not an exc–","TWN":"才不是辯解……！"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그게 실전이었잖아?","JPN":"あれが実戦だったらって考えてみろよ。","ENG":"If that were a real battle...","TWN":"如果那是實戰呢？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"넌 평생 네 분대원들을 사지로 밀어 넣은 폐급 새끼 취급 받았어.","JPN":"あんたは一生、分隊員を死地に追いやったクズ扱いされるほどのことだったんだ。","ENG":"Then you would've been condemned for life, being called a piece of trash who put her teammates' lives at risk.","TWN":"那樣的話，你要當一輩子把小隊員送上死路的廢物嗎？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};